 48→    const existing = byFile.get(c.filePath);
 49→    if (existing) existing.push(c);
 50→    else byFile.set(c.filePath, [c]);
 51→  }
 52→
 53→  return (
 54→    <div
 55→      className="sticky bottom-0 z-20 border-t"
 56→      style={{
 57→        borderColor: "var(--color-accent)",
 58→        backgroundColor: "var(--color-bg-raised)",
 59→      }}
 60→    >
 61→      {/* Expanded comment list */}
 62→      {expanded && (
 63→        <div className="max-h-[240px] overflow-y-auto border-b border-border-subtle px-4 py-3">
 64→          {[...byFile.entries()].map(([filePath, fileComments]) => (
 65→            <div key={filePath} className="mb-3 last:mb-0">
 66→              <p className="mb-1 font-mono text-[11px] font-medium text-accent-fg">
 67→                {filePath}
 68→              </p>
 69→              {fileComments
 70→                .sort((a, b) => a.lineNumber - b.lineNumber)
 71→                .map((c) => (
 72→                  <div
 73→                    key={c.id}
 74→                    className="ml-3 flex items-baseline gap-2 py-0.5"
 75→                  >
 76→                    <span className="shrink-0 font-mono text-[10px] text-fg-subtle">
 77→                      L{c.lineNumber}
 78→                    </span>
 79→                    <span className="text-xs text-fg-muted">{c.comment}</span>
 80→                  </div>
 81→                ))}
 82→            </div>
 83→          ))}
 84→        </div>
 85→      )}
 86→
 87→      {/* Bar */}
 88→      <div className="flex items-center gap-3 px-4 py-2">
 89→        <button
 90→          onClick={() => setExpanded(!expanded)}
 91→          className="flex items-center gap-1.5 text-fg-muted transition-colors hover:text-fg"
 92→        >
 93→          <MessageSquare size={14} style={{ color: "var(--color-accent-fg)" }} />
 94→          <span className="text-xs font-medium">
 95→            {comments.length} comment{comments.length !== 1 ? "s" : ""}{" "}
 96→            <span className="font-normal text-fg-subtle">
 97→              across {fileCount} file{fileCount !== 1 ? "s" : ""}
 98→            </span>
 99→          </span>
100→          {expanded ? <ChevronDown size={12} /> : <ChevronUp size={12} />}
101→        </button>
102→
103→        <div className="ml-auto flex items-center gap-2">
104→          {/* Agent picker */}
105→          <select
106→            value={agent}
107→            onChange={(e) =>
108→              setAgent(e.target.value as "claude-code" | "codex")
109→            }
110→            className="rounded border border-border-subtle bg-bg px-2 py-1 text-[11px] text-fg-muted outline-none focus:border-accent"
111→          >
112→            <option value="claude-code">Claude Code</option>
113→            <option value="codex">Codex</option>
114→          </select>
115→
116→          {/* Copy Prompt */}
117→          <button
118→            onClick={handleCopy}
119→            className="flex items-center gap-1 rounded border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-fg-subtle hover:text-fg"
120→          >
121→            <Clipboard size={11} />
122→            {copied ? "Copied!" : "Copy Prompt"}
123→          </button>
124→
125→          {/* Clear All */}
126→          <button
127→            onClick={onClearAll}
128→            className="flex items-center gap-1 rounded px-2 py-1 text-[11px] text-fg-subtle transition-colors hover:text-red"
129→            title="Clear all comments"
130→          >
131→            <Trash2 size={11} />
132→          </button>
133→
